(function($) {
    $(document).ready(function() {
        $('.lzaws-settings').each(function() {
            var $container = $(this);

            $('select.bucket', $container).change(function() {
                var $select = $(this);

                if ($select.val() !== 'new') {
                    return;
                }

                var error_func = function(jqXHR, textStatus, errorThrown) {
                    alert(lzaws_i18n.create_bucket_error + errorThrown);
                    $select[0].selectedIndex = 0;
                    console.log(jqXHR);
                    console.log(textStatus);
                    console.log(errorThrown);
                };

                var success_func = function(data, textStatus, jqXHR) {
                    if (typeof data['success'] !== 'undefined') {
                        var opt = document.createElement('option');
                        opt.value = opt.innerHTML = bucket_name;
                        var inserted_at_position = 0;
                        $('option', $select).each(function() {
                            // For some reason, no error occurs when
                            // adding a bucket you've already added
                            if ($(this).val() == bucket_name) {
                                return false;
                            }
                            if ($(this).val() > bucket_name) {
                                $(opt).insertBefore($(this));
                                return false;
                            }
                            inserted_at_position = inserted_at_position + 1;
                        });
                        $select[0].selectedIndex = inserted_at_position;

                        // If they decided to create a new bucket before refreshing
                        // the page, we need another nonce
                        lzaws_i18n.create_bucket_nonce = data['_nonce'];
                    }
                    else {
                        alert(lzaws_i18n.create_bucket_error + data['error']);
                        $select[0].selectedIndex = 0;
                    }
                };

                var bucket_name = window.prompt(lzaws_i18n.create_bucket_prompt);
                if (!bucket_name) {
                    $select[0].selectedIndex = 0;
                    return;
                }

                var data = {
                    action: 'lzaws-create-bucket',
                    bucket_name: bucket_name,
                    _nonce: lzaws_i18n.create_bucket_nonce
                };

                $.ajax({
                    url: ajaxurl,
                    type: 'POST',
                    dataType: 'JSON',
                    success: success_func,
                    error: error_func,
                    data: data
                });
            });

        });
        $('#listBucket').click(function() {
            var $container = $('.s3bucket-list');
            $container.empty();
            $container.append('<p>Listing S3 bucket, please wait...</p>');

            var error_func = function(jqXHR, textStatus, errorThrown) {
                alert(lzaws_i18n.list_bucket_error + errorThrown);
                console.log(jqXHR);
                console.log(textStatus);
                console.log(errorThrown);
            };

            var success_func = function(data, textStatus, jqXHR) {
                if (typeof data['success'] !== 'undefined') {
                    $container.empty();
                    var $bucketlist = data['data'];
                    for (i=0; i < $bucketlist.length; i++) {
                        $obj = '<span style="display:inline-block; width:40%">' + $bucketlist[i].file + '</span><span style="display:inline-block; width:10%">--></span><span style="display:inline-block; width:50%">' + $bucketlist[i].title + '<br/>';
                        $container.append($obj);
                    }
                    lzaws_i18n.list_bucket_nonce = data['_nonce'];
                } else {
                    alert(lzaws_i18n.list_bucket_error + data['error']);
                }
            };

            var bucket_name = $('.bucket').val();
            var prefix = $('#object-prefix').val();
            if (!bucket_name || !prefix) {
                return;
            }

            var data = {
                action: 'lzaws-list-bucket',
                bucket_name: bucket_name,
                prefix: prefix,
                _nonce: lzaws_i18n.list_bucket_nonce
            };

            var listCall = $.ajax({
                url: ajaxurl,
                type: 'POST',
                dataType: 'JSON',
                success: success_func,
                error: error_func,
                data: data
            });

        });
        $('#regenerate').click(function() {
            var $container = $('.s3bucket-list');
            $container.empty();
            $container.append('<p>Regenerating attachment links, please wait...</p>');

            var error_func = function(jqXHR, textStatus, errorThrown) {
                alert(lzaws_i18n.regenerate_error + errorThrown);
                console.log(jqXHR);
                console.log(textStatus);
                console.log(errorThrown);
            };

            var success_func = function(data, textStatus, jqXHR) {
                if (typeof data['success'] !== 'undefined') {
                    $container.empty();
                    var $bucketlist = data['data'];
                    for (i=0; i < $bucketlist.length; i++) {
                        $obj = '<span style="display:inline-block; width:40%">' + $bucketlist[i].file + '</span><span style="display:inline-block; width:10%">--></span><span style="display:inline-block; width:50%">' + $bucketlist[i].status + '<br/>';
                        $container.append($obj);
                    }
                    lzaws_i18n.regenerate_nonce = data['_nonce'];
                } else {
                    alert(lzaws_i18n.regenerate_error + data['error']);
                }
            };

            var bucket_name = $('.bucket').val();
            var prefix = $('#object-prefix').val();
            var cloudfront = $('#cloudfront').val();
            var regenerate_ids = $('#regenerate_ids').val();
            if (!bucket_name || !prefix) {
                return;
            }

            var data = {
                action: 'lzaws-regenerate',
                bucket_name: bucket_name,
                prefix: prefix,
                cloudfront: cloudfront,
                regenerate_ids: regenerate_ids,
                _nonce: lzaws_i18n.regenerate_nonce
            };

            var listCall = $.ajax({
                url: ajaxurl,
                type: 'POST',
                dataType: 'JSON',
                success: success_func,
                error: error_func,
                data: data
            });

        });

        $('#update-featured-images').click(function() {
            var $container = $('.s3bucket-list');
            $container.empty();
            $container.append('<p>Updating featured images, please wait...</p>');

            var error_func = function(jqXHR, textStatus, errorThrown) {
                alert(lzaws_i18n.regenerate_error + errorThrown);
                console.log(jqXHR);
                console.log(textStatus);
                console.log(errorThrown);
            };

            var success_func = function(data, textStatus, jqXHR) {
                if (typeof data['success'] !== 'undefined') {
                    $container.empty();
                    var $bucketlist = data['data'];
                    for (i=0; i < $bucketlist.length; i++) {
                        $obj = '<span style="display:inline-block; width:40%">' + $bucketlist[i].file + '</span><span style="display:inline-block; width:10%">--></span><span style="display:inline-block; width:50%">' + $bucketlist[i].status + '<br/>';
                        $container.append($obj);
                    }
                    lzaws_i18n.update_featured_images_nonce = data['_nonce'];
                } else {
                    alert(lzaws_i18n.update_featured_images_error + data['error']);
                }
            };

            var data = {
                action: 'lzaws-update-featured-images',
                _nonce: lzaws_i18n.update_featured_images_nonce
            };

            var listCall = $.ajax({
                url: ajaxurl,
                type: 'POST',
                dataType: 'JSON',
                success: success_func,
                error: error_func,
                data: data
            });

        });

    });

})(jQuery);

